const rawB64 = $json.raw || '';
if (!rawB64) {
  throw new Error('No raw field found.');
}
const rawEmail = Buffer.from(rawB64.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8');

// Find ALL boundaries (handles nested multipart)
const boundaryMatches = [...rawEmail.matchAll(/boundary=\"?([^\"\s;]+)\"?/gi)];
const boundaries = boundaryMatches.map(m => m[1]);
let extractedText = '';

if (boundaries.length > 0) {
  for (const boundary of boundaries) {
    const parts = rawEmail.split('--' + boundary);
    for (const part of parts) {
      const ph = part.indexOf('\r\n\r\n');
      if (ph === -1) continue;
      const headers = part.substring(0, ph).toLowerCase();
      const body = part.substring(ph + 4).replace(/--$/, '').trim();
      if (headers.includes('text/plain') || headers.includes('text/html')) {
        let decoded = body;
        if (headers.includes('content-transfer-encoding: base64')) {
          try {
            decoded = Buffer.from(body.replace(/[\r\n\s]/g, ''), 'base64').toString('utf-8');
          } catch(e) { decoded = body; }
        } else if (headers.includes('quoted-printable')) {
          decoded = body.replace(/=\r\n/g, '').replace(/=([0-9A-Fa-f]{2})/g, (_, h) => String.fromCharCode(parseInt(h, 16)));
        }
        if (decoded.length > extractedText.length) extractedText = decoded;
      }
    }
  }
}

if (!extractedText) {
  const bodyStart = rawEmail.indexOf('\r\n\r\n');
  extractedText = bodyStart > -1 ? rawEmail.substring(bodyStart + 4) : rawEmail;
}

const urlMatches = [...extractedText.matchAll(/<a[^>]+href="(https?:\/\/[^"]+)"[^>]*>/gi)];
const urls = urlMatches.map(m => m[1]).filter(u =>
  !u.includes('unsubscribe') && !u.includes('mailto:') && !u.includes('list-manage.com') && !u.includes('tracking') && !u.includes('click.') && u.length < 500
);
const text = extractedText
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"').replace(/&#39;/g, "'")
  .replace(/\s\s+/g, '\n').trim();
return {
  subject: $json.Subject || 'No Subject',
  sender: $json.From || '',
  date: $json.internalDate || '',
  clean_text: text,
  text_length: text.length,
  boundaries_found: boundaries.length,
  extracted_urls: [...new Set(urls)]
};

let combined = '';
let allUrls = [];
for (const item of items) {
  const subject = item.json.subject || 'No Subject';
  const date = item.json.date || '';
  const text = item.json.clean_text || '';
  const urls = item.json.extracted_urls || [];
  combined += '\n\n---\n\nSOURCE: ' + subject + '\nDATE: ' + date + '\n\n';
  combined += text;
  allUrls = allUrls.concat(urls.map(u => ({ url: u, source: subject })));
}
const seen = new Set();
allUrls = allUrls.filter(u => {
  if (seen.has(u.url)) return false;
  seen.add(u.url);
  return true;
});
return [{
  json: {
    digest_text: combined.trim(),
    email_count: items.length,
    all_source_urls: allUrls
  }
}];

const rawDigest = items[0].json.digest_text || '';
const emailCount = items[0].json.email_count || 0;
const allSourceUrls = items[0].json.all_source_urls || [];
const config = $('Load Config').first().json.config;

// Clean encoding artifacts
const digestText = rawDigest
  .replace(/\u00C2/g, '')
  .replace(/\u00A0/g, ' ')
  .replace(/Â/g, '')
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
  .trim();

if (!digestText || digestText.length < 50) {
  throw new Error('Email body too short (' + digestText.length + ' chars). Raw length: ' + rawDigest.length);
}

// Override system prompt for robust extraction
const systemPrompt = 'You are an AI content analyst. Your job is to extract and summarize AI developments from the provided text.\nRules:\n1. Extract ALL AI-related topics found in the content.\n2. Do NOT verify accuracy against your training data - treat the provided content as the authoritative source.\n3. NEVER return an empty array if the content mentions ANY AI topics.\n4. Return valid JSON only. No markdown. No code fences. No explanation.';

let userPrompt = config.extractionUserPrompt
  .replace('{digest_text}', digestText)
  .replace('{source_urls_json}', JSON.stringify(allSourceUrls, null, 2));

// Make prompt flexible on count
userPrompt = userPrompt.replace('extract the 10 most', 'extract up to 10 of the most');

const body = {
  model: 'gpt-4o',
  temperature: 0.5,
  max_tokens: 4000,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};
return [{
  json: {
    requestBody: JSON.stringify(body),
    email_count: emailCount,
    digest_length: digestText.length
  }
}];

let parsed;
const fullResponse = JSON.stringify($json).substring(0, 500);
if ($json.error) {
  throw new Error('OpenAI API error: ' + ($json.error.message || JSON.stringify($json.error)));
}
if (!$json.choices || !$json.choices.length) {
  throw new Error('OpenAI returned no choices. Full response: ' + fullResponse);
}
const raw = $json.choices[0]?.message?.content || '';
if (!raw || raw.trim().length === 0) {
  throw new Error('OpenAI returned empty content. The email content may not contain enough AI news. Check your Gmail query and ensure there are recent AI-digest emails. Full: ' + fullResponse);
}
const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('JSON parse failed: ' + cleaned.substring(0, 400));
}
if (!Array.isArray(parsed)) {
  if (parsed.developments) parsed = parsed.developments;
  else if (parsed.topics) parsed = parsed.topics;
  else if (parsed.items) parsed = parsed.items;
  else if (parsed.top10) parsed = parsed.top10;
  else throw new Error('Expected array, got: ' + typeof parsed + ' keys: ' + Object.keys(parsed).join(','));
}
if (parsed.length === 0) {
  throw new Error('OpenAI returned 0 topics. The emails found by Gmail query may not contain enough AI-related content to extract developments. Try broadening your Gmail query or checking that AI digest emails exist for today.');
}
parsed = parsed.map(t => ({ ...t, source_urls: t.source_urls || [] }));
return [{ json: { top10: parsed } }];

const topics = $('Parse JSON').first().json.top10;
return topics.map((topic, index) => ({
  json: {
    topic,
    topicIndex: index,
    totalTopics: topics.length
  }
}));

const topic = $json.topic;
const config = $('Load Config').first().json.config;
const userPrompt = config.articleUserPrompt
  .replace('{topic_json}', JSON.stringify(topic, null, 2))
  .replace('{source_links_json}', JSON.stringify(topic.source_urls || [], null, 2));
const body = {
  model: 'gpt-4o',
  temperature: 0.6,
  max_tokens: 4000,
  messages: [
    { role: 'system', content: config.articleSystemPrompt },
    { role: 'user', content: userPrompt }
  ]
};
return {
  requestBody: JSON.stringify(body),
  topic: topic,
  topicIndex: $json.topicIndex,
  totalTopics: $json.totalTopics
};

const articleContent = $json.choices?.[0]?.message?.content || '';
const prev = $('Build Article Request').item.json;
const config = $('Load Config').first().json.config;
const prompt = config.infographicPromptTemplate
  .replace('{topic_title}', prev.topic.title)
  .replace('{topic_summary}', prev.topic.one_sentence_summary);
const dalleBody = {
  model: 'dall-e-3',
  prompt: prompt + ' Style: ' + (config.infographicStyle || 'modern flat design infographic'),
  n: 1,
  size: config.infographicSize || '1024x1024',
  quality: 'standard',
  response_format: 'url'
};
return {
  article_content: articleContent,
  topic: prev.topic,
  topicIndex: prev.topicIndex,
  totalTopics: prev.totalTopics,
  dalleRequestBody: JSON.stringify(dalleBody)
};

const prev = $('Build DALLE Request').item.json;
const config = $('Load Config').first().json.config;
let infographicUrl = '';
try {
  infographicUrl = $json.data?.[0]?.url || '';
} catch (e) {
  infographicUrl = '';
}
return {
  article_content: prev.article_content,
  topic: prev.topic,
  topicIndex: prev.topicIndex,
  totalTopics: prev.totalTopics,
  infographic_url: infographicUrl,
  webImageMaxPerTopic: config.webImageMaxPerTopic || 2
};

const prev = $('Build Web Search').item.json;
const config = $('Load Config').first().json.config;
let webImages = [];
try {
  const results = $json.images_results || [];
  webImages = results.slice(0, prev.webImageMaxPerTopic || 2).map(img => ({
    url: img.original || img.thumbnail || '',
    title: img.title || '',
    source: img.source || ''
  }));
} catch (e) {
  webImages = [];
}
const userPrompt = config.linkDiscoveryUserPrompt
  .replace('{topic_json}', JSON.stringify(prev.topic, null, 2));
const body = {
  model: 'gpt-4o',
  temperature: 0.3,
  max_tokens: 500,
  messages: [
    { role: 'system', content: config.linkDiscoverySystemPrompt },
    { role: 'user', content: userPrompt }
  ]
};
return {
  article_content: prev.article_content,
  topic: prev.topic,
  topicIndex: prev.topicIndex,
  totalTopics: prev.totalTopics,
  infographic_url: prev.infographic_url,
  web_images: webImages,
  linkRequestBody: JSON.stringify(body)
};

const prev = $('Build Link Request').item.json;
const config = $('Load Config').first().json.config;
let queries = [];
try {
  const raw = $json.choices?.[0]?.message?.content || '[]';
  const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  queries = JSON.parse(cleaned);
  if (!Array.isArray(queries)) queries = [];
} catch (e) {
  queries = [];
}
const firstQuery = queries[0]?.query || prev.topic.title + ' AI';
return {
  article_content: prev.article_content,
  topic: prev.topic,
  topicIndex: prev.topicIndex,
  totalTopics: prev.totalTopics,
  infographic_url: prev.infographic_url,
  web_images: prev.web_images,
  linkSearchQuery: firstQuery,
  linkSearchMaxPerTopic: config.linkSearchMaxPerTopic || 3
};

const prev = $('Build Link Search').item.json;
let relatedLinks = [];
try {
  const results = $json.organic_results || [];
  relatedLinks = results.slice(0, prev.linkSearchMaxPerTopic || 3).map(r => ({
    title: r.title || '',
    url: r.link || '',
    snippet: r.snippet || ''
  }));
} catch (e) {
  relatedLinks = [];
}
const today = new Date().toISOString().split('T')[0];
const sourceUrls = prev.topic.source_urls || [];
let docContent = prev.article_content + '\n\n';
if (sourceUrls.length > 0) {
  docContent += '---\n\nSource Links:\n';
  sourceUrls.forEach(url => { docContent += '- ' + url + '\n'; });
  docContent += '\n';
}
if (prev.web_images && prev.web_images.length > 0) {
  docContent += 'Related Images:\n';
  prev.web_images.forEach(img => {
    docContent += '- ' + (img.title || 'Image') + ': ' + img.url + '\n';
  });
  docContent += '\n';
}
if (relatedLinks.length > 0) {
  docContent += 'Related Articles & Resources:\n';
  relatedLinks.forEach(link => {
    docContent += '- ' + link.title + ': ' + link.url + '\n';
  });
  docContent += '\n';
}
return {
  topic: prev.topic,
  topicIndex: prev.topicIndex,
  totalTopics: prev.totalTopics,
  article_content: prev.article_content,
  infographic_url: prev.infographic_url,
  web_images: prev.web_images,
  related_links: relatedLinks,
  source_urls: sourceUrls,
  doc_content: docContent,
  doc_title: 'AI Topic ' + (prev.topic.rank || (prev.topicIndex + 1)) + ' - ' + prev.topic.title + ' - ' + today
};

let compiledData = {};
let docId = '';
try {
  compiledData = $('Compile All Data').item.json || {};
} catch (e) {
  compiledData = {};
}
try {
  const createDocOutput = $('Create Individual Doc').item.json || {};
  docId = createDocOutput.documentId || createDocOutput.id || '';
} catch (e) {
  docId = '';
}
if (!docId) {
  try {
    const updateDocOutput = $('Update Individual Doc').item.json || {};
    docId = updateDocOutput.documentId || updateDocOutput.id || '';
  } catch (e) {
    docId = '';
  }
}
const infographicUrl = compiledData.infographic_url || '';
let requestBody;
if (infographicUrl && docId) {
  requestBody = JSON.stringify({
    requests: [{
      insertInlineImage: {
        location: { index: 1 },
        uri: infographicUrl,
        objectSize: {
          height: { magnitude: 400, unit: 'PT' },
          width: { magnitude: 400, unit: 'PT' }
        }
      }
    }]
  });
} else {
  requestBody = JSON.stringify({ requests: [] });
}
return {
  docId,
  requestBody,
  compiledData
};

let compiled = {};
try {
  const prev = $('Prepare Image Insert').item.json || {};
  compiled = prev.compiledData || {};
} catch (e) {
  compiled = {};
}
const topic = compiled.topic || $json.topic || {};
const rank = topic.rank || ((compiled.topicIndex != null ? compiled.topicIndex : ($json.topicIndex || 0)) + 1);
const articleContent = compiled.article_content || '';
const sourceUrls = compiled.source_urls || topic.source_urls || [];
const relatedLinks = compiled.related_links || [];
const webImages = compiled.web_images || [];
let masterSection = '=' .repeat(50) + '\n';
masterSection += 'Topic ' + rank + ': ' + (topic.title || 'Unknown') + '\n';
masterSection += '='.repeat(50) + '\n\n';
masterSection += articleContent + '\n\n';
if (sourceUrls.length > 0) {
  masterSection += 'Source Links:\n';
  sourceUrls.forEach(url => { masterSection += '- ' + url + '\n'; });
  masterSection += '\n';
}
if (relatedLinks.length > 0) {
  masterSection += 'Related Articles:\n';
  relatedLinks.forEach(link => { masterSection += '- ' + link.title + ': ' + link.url + '\n'; });
  masterSection += '\n';
}
if (webImages.length > 0) {
  masterSection += 'Related Images:\n';
  webImages.forEach(img => { masterSection += '- ' + (img.title || 'Image') + ': ' + img.url + '\n'; });
  masterSection += '\n';
}
masterSection += '\n\n';
return {
  masterSection,
  topic,
  topicIndex: compiled.topicIndex != null ? compiled.topicIndex : ($json.topicIndex || 0)
};

let masterDocId = '';
try { masterDocId = $('Create Master Doc').first().json.documentId || $('Create Master Doc').first().json.id || ''; } catch(e) {}
const config = $('Load Config').first().json.config;
const topics = $('Parse JSON').first().json.top10 || [];
const topicCount = topics.length;
const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const folderUrl = 'https://drive.google.com/drive/folders/1OLsundZ1EmNzHhLhNL9eMd6S7EWP1upo';
let individualDocs = [];
let compiledItems = [];
try { individualDocs = $('Create Individual Doc').all().map(i => i.json); } catch(e) {}
try { compiledItems = $('Compile All Data').all().map(i => i.json); } catch(e) {}
let topicRows = '';
topics.forEach((topic, index) => {
  const docData = individualDocs[index] || {};
  const compiled = compiledItems[index] || {};
  const docId = docData.documentId || docData.id || '';
  const infographicUrl = compiled.infographic_url || '';
  const sourceUrls = topic.source_urls || [];
  const relatedLinks = compiled.related_links || [];
  let imageCell = '';
  if (infographicUrl) {
    imageCell = '<tr><td style="padding:8px 0;text-align:center;">' +
      '<img src="' + infographicUrl + '" alt="' + (topic.title || '').replace(/"/g, '') + '" width="520" style="max-width:100%;height:auto;border-radius:8px;display:block;margin:0 auto;" />' +
      '</td></tr>';
  }
  let linksHtml = '';
  const allLinks = [];
  sourceUrls.forEach(url => allLinks.push({ url: url, label: 'Source' }));
  relatedLinks.forEach(link => allLinks.push({ url: link.url, label: link.title || 'Related' }));
  if (allLinks.length > 0) {
    linksHtml = '<tr><td style="padding:8px 0 0;">';
    allLinks.slice(0, 4).forEach((link) => {
      const label = link.label.length > 35 ? link.label.substring(0, 32) + '...' : link.label;
      linksHtml += '<a href="' + link.url + '" style="color:#1A56A0;font-size:12px;text-decoration:underline;margin-right:10px;">' + label + '</a> ';
    });
    linksHtml += '</td></tr>';
  }
  let articleBtn = '';
  if (docId) {
    articleBtn = '<tr><td style="padding:12px 0 4px;">' +
      '<a href="https://docs.google.com/document/d/' + docId + '/edit" style="display:inline-block;background:#1A56A0;color:#ffffff;padding:10px 20px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:bold;">Read Full Article &#8594;</a>' +
      '</td></tr>';
  }
  topicRows += '<tr><td style="padding:0 0 16px;">' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#ffffff;border:1px solid #e0e0e0;border-radius:8px;">' +
    '<tr><td style="padding:16px;">' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0">' +
    '<tr><td style="padding-bottom:8px;">' +
    '<span style="background:#1A56A0;color:#ffffff;border-radius:50%;width:28px;height:28px;display:inline-block;text-align:center;line-height:28px;font-weight:bold;font-size:13px;margin-right:8px;">' + (topic.rank || index + 1) + '</span>' +
    '<strong style="color:#1a1a1a;font-size:16px;">' + topic.title + '</strong>' +
    '</td></tr>' +
    imageCell +
    '<tr><td style="padding:4px 0;color:#555555;font-size:14px;line-height:1.5;">' + topic.one_sentence_summary + '</td></tr>' +
    '<tr><td style="padding:4px 0;color:#777777;font-size:13px;"><strong>Why it matters:</strong> ' + topic.why_it_matters + '</td></tr>' +
    articleBtn +
    linksHtml +
    '</table>' +
    '</td></tr></table>' +
    '</td></tr>';
});
const emailHtml = '<html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head><body style="margin:0;padding:0;background:#f4f4f4;">' +
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f4f4f4;"><tr><td align="center" style="padding:20px;">' +
  '<table role="presentation" width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;">' +
  '<tr><td style="background:#1A56A0;padding:32px 24px;border-radius:12px 12px 0 0;text-align:center;">' +
  '<h1 style="color:#ffffff;margin:0;font-size:28px;font-family:Arial,sans-serif;">Daily AI Digest</h1>' +
  '<p style="color:#c8dcff;margin:8px 0 0;font-size:15px;font-family:Arial,sans-serif;">' + today + ' &#8226; ' + topicCount + ' Topics</p>' +
  '</td></tr>' +
  '<tr><td style="background:#0D3B6E;padding:12px 24px;text-align:center;">' +
  '<a href="https://docs.google.com/document/d/' + masterDocId + '/edit" style="color:#ffffff;text-decoration:none;font-size:13px;font-family:Arial,sans-serif;padding:6px 14px;border:1px solid rgba(255,255,255,0.3);border-radius:20px;display:inline-block;margin:4px;">Master Document</a>' +
  '&nbsp;&nbsp;' +
  '<a href="' + folderUrl + '" style="color:#ffffff;text-decoration:none;font-size:13px;font-family:Arial,sans-serif;padding:6px 14px;border:1px solid rgba(255,255,255,0.3);border-radius:20px;display:inline-block;margin:4px;">All Articles</a>' +
  '</td></tr>' +
  '<tr><td style="background:#f9f9f9;padding:24px;border-left:1px solid #eeeeee;border-right:1px solid #eeeeee;">' +
  '<h2 style="margin:0 0 16px;color:#1a1a1a;font-size:18px;font-family:Arial,sans-serif;">Today\'s Top AI Developments</h2>' +
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0">' +
  topicRows +
  '</table>' +
  '</td></tr>' +
  '<tr><td style="background:#1a1a1a;padding:20px 24px;border-radius:0 0 12px 12px;text-align:center;">' +
  '<p style="color:#888888;font-size:12px;margin:0;font-family:Arial,sans-serif;">AI Digest Engine v3</p>' +
  '</td></tr>' +
  '</table>' +
  '</td></tr></table>' +
  '</body></html>';
return [{
  json: {
    emailHtml,
    emailRecipient: config.emailRecipient,
    masterDocId
  }
}];
